import React, { useState, useEffect } from "react";
import { Link } from "react-router-dom";
import { coursesAPI } from "../services/api";
import ProgressBar from "../components/ProgressBar";
import Spinner from "../components/Spinner";

const MyCourses = () => {
  const [courses, setCourses] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState("");

  useEffect(() => {
    const fetch = async () => {
      setLoading(true);
      try {
        const { data } = await coursesAPI.getMyCourses();
        setCourses(data);
      } catch { setError("Failed to load your courses. Please try again."); }
      finally { setLoading(false); }
    };
    fetch();
  }, []);

  if (loading) return <Spinner message="Loading your courses..." />;

  const stats = [
    { icon: "bi-book-fill", val: courses.length, label: "Enrolled", color: "#6c63ff" },
    { icon: "bi-check-circle-fill", val: courses.filter(c => c.progress === 100).length, label: "Completed", color: "#43d9ad" },
    { icon: "bi-lightning-charge-fill", val: courses.filter(c => c.progress > 0 && c.progress < 100).length, label: "In Progress", color: "#ffbb57" },
    { icon: "bi-bullseye", val: courses.length > 0 ? Math.round(courses.reduce((a,c)=>a+(c.progress||0),0)/courses.length)+"%" : "0%", label: "Avg Progress", color: "#ff6584" }
  ];

  return (
    <div className="py-5">
      <div className="container">
        {/* Header */}
        <div className="d-flex justify-content-between align-items-start flex-wrap gap-3 mb-5">
          <div>
            <h1 className="fw-bold mb-1" style={{ color: "#e8e8f0", fontSize: "2rem" }}>My Learning</h1>
            <p className="mb-0" style={{ color: "#9999bb" }}>
              {courses.length > 0 ? `Enrolled in ${courses.length} course${courses.length !== 1 ? "s" : ""}` : "Start your learning journey today"}
            </p>
          </div>
          <Link to="/" className="btn fw-semibold" style={{ background: "#6c63ff", color: "white", border: "none", borderRadius: 10, padding: "10px 22px" }}>
            <i className="bi bi-plus-circle me-2"></i>Browse Courses
          </Link>
        </div>

        {error && <div className="alert mb-4" style={{ background: "rgba(255,101,132,0.1)", border: "1px solid #ff6584", color: "#ff6584", borderRadius: 10 }}>{error}</div>}

        {courses.length === 0 ? (
          <div className="text-center py-5">
            <div style={{ fontSize: "4rem" }} className="mb-3">📖</div>
            <h4 className="fw-bold mb-2" style={{ color: "#e8e8f0" }}>No courses yet</h4>
            <p style={{ color: "#9999bb" }}>Enroll in a course to start learning</p>
            <Link to="/" className="btn fw-bold mt-2" style={{ background: "#6c63ff", color: "white", border: "none", borderRadius: 10, padding: "12px 28px" }}>
              Explore Courses
            </Link>
          </div>
        ) : (
          <>
            {/* Stats */}
            <div className="row g-3 mb-5">
              {stats.map((s, i) => (
                <div key={i} className="col-6 col-lg-3">
                  <div className="card border-0 p-3 d-flex flex-row align-items-center gap-3" style={{ background: "#1a1a2e", border: "1px solid #2a2a4a !important", borderRadius: 12 }}>
                    <div className="d-flex align-items-center justify-content-center rounded-circle"
                      style={{ width: 44, height: 44, background: `${s.color}20`, flexShrink: 0 }}>
                      <i className={`bi ${s.icon}`} style={{ color: s.color, fontSize: "1.2rem" }}></i>
                    </div>
                    <div>
                      <div className="fw-bold fs-5" style={{ color: "#e8e8f0" }}>{s.val}</div>
                      <div className="small" style={{ color: "#666688" }}>{s.label}</div>
                    </div>
                  </div>
                </div>
              ))}
            </div>

            {/* Course Cards */}
            <div className="row g-4">
              {courses.map(course => (
                <div key={course._id} className="col-12 col-md-6 col-lg-4">
                  <div className="card border-0 h-100" style={{
                    background: "#1a1a2e", border: "1px solid #2a2a4a !important",
                    borderRadius: 14, overflow: "hidden",
                    transition: "transform 0.2s, box-shadow 0.2s"
                  }}
                    onMouseEnter={e => { e.currentTarget.style.transform = "translateY(-3px)"; e.currentTarget.style.boxShadow = "0 8px 32px rgba(108,99,255,0.2)"; }}
                    onMouseLeave={e => { e.currentTarget.style.transform = "translateY(0)"; e.currentTarget.style.boxShadow = ""; }}
                  >
                    <div style={{ position: "relative", height: 160, overflow: "hidden" }}>
                      <img
                        src={course.thumbnail || "https://images.unsplash.com/photo-1516116216624-53e697fedbea?w=400"}
                        alt={course.title}
                        className="w-100 h-100"
                        style={{ objectFit: "cover" }}
                        onError={e => { e.target.src = "https://images.unsplash.com/photo-1516116216624-53e697fedbea?w=400"; }}
                      />
                      {course.progress === 100 && (
                        <span className="badge position-absolute" style={{ top: 10, right: 10, background: "rgba(67,217,173,0.9)", color: "#0f0f1a", borderRadius: 50, padding: "5px 12px", fontWeight: 700 }}>
                          ✅ Completed
                        </span>
                      )}
                    </div>
                    <div className="card-body d-flex flex-column gap-2 p-3">
                      <span className="small fw-bold text-uppercase" style={{ color: "#6c63ff", letterSpacing: "0.06em" }}>{course.category}</span>
                      <h5 className="fw-bold mb-0" style={{ color: "#e8e8f0", fontSize: "0.97rem" }}>{course.title}</h5>
                      <p className="small mb-0" style={{ color: "#666688" }}>
                        <i className="bi bi-person-fill me-1" style={{ color: "#6c63ff" }}></i>{course.instructor}
                      </p>
                      <ProgressBar progress={course.progress || 0} />
                      <div className="d-flex gap-3">
                        <span className="small" style={{ color: "#666688" }}><i className="bi bi-collection-play me-1"></i>{course.lessons?.length} lessons</span>
                        <span className="small" style={{ color: "#666688" }}><i className="bi bi-clock me-1"></i>{course.duration}</span>
                      </div>
                      <div className="d-flex gap-2 mt-auto">
                        <Link to={`/player/${course._id}`} className="btn btn-sm fw-semibold flex-grow-1" style={{ background: "#6c63ff", color: "white", border: "none", borderRadius: 8 }}>
                          {course.progress === 100 ? "Review" : course.progress > 0 ? "Continue" : "Start"}
                        </Link>
                        <Link to={`/course/${course._id}`} className="btn btn-sm" style={{ border: "1px solid #2a2a4a", color: "#9999bb", borderRadius: 8 }}>
                          Details
                        </Link>
                      </div>
                    </div>
                  </div>
                </div>
              ))}
            </div>
          </>
        )}
      </div>
    </div>
  );
};

export default MyCourses;
